// Define South African real estate Facebook groups to monitor
const groups = [
  { id: '123456789', name: 'Cape Town Properties For Sale', location: 'Cape Town' },
  { id: '234567890', name: 'Johannesburg Real Estate', location: 'Johannesburg' },
  { id: '345678901', name: 'Durban Properties', location: 'Durban' },
  { id: '456789012', name: 'Pretoria Houses For Sale', location: 'Pretoria' },
  { id: '567890123', name: 'South Africa Property Investment', location: 'National' },
  { id: '678901234', name: 'Cape Winelands Properties', location: 'Stellenbosch' },
  { id: '789012345', name: 'Garden Route Real Estate', location: 'George' }
];

return groups.map(g => ({ json: g }));

const data = $input.first().json;
const posts = data.posts || [];
const groupName = $('Load Group List').item.json.name;
const groupLocation = $('Load Group List').item.json.location;
const processedAt = new Date().toISOString();

// Keywords that suggest a property listing
const listingKeywords = ['for sale', 'te koop', 'bedroom', 'bathroom', 'r 1', 'r 2', 'r 3', 'r 4', 'r 5', 'r 6', 'r 7', 'r 8', 'r 9', 'r 10', 'selling', 'property', 'house', 'apartment', 'plot', 'land'];

const isListing = (text) => {
  const lower = text.toLowerCase();
  return listingKeywords.some(kw => lower.includes(kw));
};

const extractPrice = (text) => {
  // Patterns: R1500000, R 1,500,000, R1.5m, 1500000
  const patterns = [
    /R\s?([\d][\d\s,]{2,})/gi,
    /R\s?([\d\.]+)\s*(?:million|m|mil)/gi,
    /([\d][\d\s,]{5,})\s*(?:rand|zar)/gi
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      let priceStr = match[0].replace(/[R\s,]/gi, '');
      if (priceStr.toLowerCase().includes('m')) {
        priceStr = parseFloat(priceStr) * 1000000;
      }
      const price = parseFloat(priceStr);
      if (price > 50000 && price < 100000000) return price;
    }
  }
  return 0;
};

const filteredPosts = posts
  .filter(post => isListing(post.text || ''))
  .map(post => ({
    listing_id: `fb_group_${post.post_id}`,
    title: (post.text || '').substring(0, 100),
    description: post.text || '',
    price: extractPrice(post.text || ''),
    price_currency: 'ZAR',
    source: 'facebook_group',
    source_group: groupName,
    city: groupLocation,
    province: post.province || '',
    url: `https://www.facebook.com/groups/${data.group_id}/posts/${post.post_id}`,
    seller_name: post.author?.name || '',
    seller_profile: post.author?.profile_url || '',
    images: post.images || [],
    post_date: post.created_time || processedAt,
    scraped_at: processedAt,
    status: 'active',
    property_type: 'unknown',
    bedrooms: 0,
    bathrooms: 0,
    suburb: '',
    size_sqm: 0
  }));

return filteredPosts.map(p => ({ json: p }));
